export const KB_DOCS: Record<string, KnowledgeBaseDocument> = {
  "accessibility": { id: "accessibility", title: "Accessibility", purpose: "Provide authoritative reference knowledge for evaluating and improving accessibility in UI/UX designs (web and mobile-inspired patterns) and for producing consistent accessibility annotations (e.g., greenlines, focus order, labels, landmarks) aligned with WCAG 2.2 and common enterprise review practices.", scope: "Applies to user-facing UI design review: structure, navigation, focus, keyboard, touch targets, contrast, text alternatives, form labeling and errors, help and authentication usability, and assistive-technology compatibility. Includes practical mapping to an annotation workflow (e.g., CVS Web Accessibility Annotation Kit components). Excludes assistant behavior, tone, output formatting rules, schema enforcement, and runtime tool/DS rules.", definitions: ["### WCAG 2.2", "Web Content Accessibility Guidelines 2.2: a W3C standard organized by four principles (Perceivable, Operable, Understandable, Robust) with testable Success Criteria at A/AA/AAA levels.", "### POUR", "The four WCAG principles: Perceivable (can be sensed), Operable (can be used), Understandable (can be understood), Robust (works with assistive tech).", "### Success Criterion (SC)", "A testable requirement in WCAG. Conformance is determined by meeting applicable SCs at a chosen level (A/AA/AAA).", "### Focus Indicator", "A visible styling change that shows which element is currently focused for keyboard interaction (e.g., outline/ring).", "### Accessible Name", "The programmatic label announced by assistive technologies for a control (derived from label text, aria-label, etc.).", "### Greenlines (Annotation)", "A common accessibility annotation technique that visually documents accessibility requirements on a design (e.g., labels, headings, focus order, landmarks, states) so engineers can implement them consistently.", "### CVS Web Accessibility Annotation Kit", "A set of Figma components and patterns for documenting accessibility requirements (e.g., focus order, labels, landmarks) in design files; used as a reference mapping for how to annotate accessibility requirements."], rulesConstraints: ["Evaluate accessibility using POUR: ensure content is perceivable, operable via keyboard, understandable in language and interaction, and robust with assistive technologies.", "Default target level for product UX validation is typically WCAG 2.2 AA unless stated otherwise.", "Do not rely on color alone to convey meaning (errors, selection, status). Always provide text and/or iconography with accessible labeling.", "Ensure interactive elements have a clear keyboard focus indicator and a logical focus order matching the visual and reading order.", "Avoid focus being hidden by sticky headers, modals, or overlays; focused element must remain at least partially visible (WCAG 2.2 adds AA focus-not-obscured minimum).", "Ensure touch targets are large enough and spaced to reduce accidental activation (WCAG 2.2 adds AA target size minimum).", "Ensure drag-only interactions have a non-drag alternative (WCAG 2.2 adds AA dragging movements).", "Forms must provide labels or instructions, identify errors in text, and provide suggestions for correction when possible.", "Authentication flows must not depend solely on memory/complex puzzles; provide accessible alternatives and allow password managers (WCAG 2.2 adds accessible authentication minimum at AA).", "When documenting accessibility in Figma, annotate requirements that are not reliably inferable from visuals alone (accessible name, role, state, focus order, error associations, keyboard behavior)."], doDont: { do: ["Use semantic structure: headings, sections, and groups should have meaningful hierarchy and labels.", "Provide sufficient color contrast for text and essential UI elements; ensure non-text contrast for icons, focus rings, and controls.", "Design for keyboard first: all controls operable without a mouse; tab order follows task flow; no keyboard traps.", "Make focus visible and consistent across components; ensure focus is not clipped or obscured by overlays.", "Design clear form labels (persistent labels preferred), required indicators, helper text, and field-level error messages bound to the field.", "Provide error identification and recovery: state what’s wrong, where, and how to fix it; focus the first invalid field on submit where appropriate.", "Ensure controls have clear accessible names that match visible labels; avoid mismatches between label text and the name announced to screen readers.", "Design touch targets with minimum size and sufficient spacing; avoid tiny icon-only tap targets without padding.", "Provide alternatives to gesture/drag-only interactions (buttons, stepper controls, plus/minus, menus).", "Annotate: focus order, landmark/region intent, accessible names for ambiguous controls, error announcement requirements, and state behaviors (disabled, loading, expanded)."], dont: ["Don’t use placeholder-only labels for inputs (placeholders disappear and reduce accessibility and usability).", "Don’t rely on color alone to communicate errors or selection (e.g., red outline only).", "Don’t hide focus indicators or make them too subtle to see against backgrounds.", "Don’t place key actions behind hover-only UI on touch-first surfaces without an alternative.", "Don’t require drag-only interactions without an equivalent control.", "Don’t design authentication or security flows that block password managers or require memorization-only steps without alternatives.", "Don’t ship forms that fail silently or show generic errors without field-level guidance."] }, examples: ["### Focus order (annotation example)", "Annotate a numeric tab order on interactive elements: 1=Primary nav, 2=Search, 3=Primary CTA, etc. Note any skip link expectation for large navs.", "### Accessible name (annotation example)", "Icon-only button shows a magnifying glass: annotate accessible name: “Search”. If there is visible text nearby, ensure the accessible name matches that text.", "### Error identification (annotation example)", "Field-level error: “Enter a valid email address (for example, name@example.com).” Annotate that the error message is programmatically associated with the input and announced on submit.", "### Contrast (annotation example)", "Annotate text contrast requirement for body text and link text, plus non-text contrast requirement for focus ring and input border states.", "### Target size (annotation example)", "Annotate minimum tap target sizing for icon buttons and spacing between adjacent targets to prevent accidental activation.", "### Drag alternative (annotation example)", "If a card reorder uses drag handles, annotate: “Provide Move up/down buttons or menu actions as a non-drag alternative.”"], edgeCases: ["When a design uses a custom component, explicitly annotate expected role, name, state, and keyboard interactions (e.g., for a custom dropdown: arrow keys, enter/escape behavior).", "When content is highly dense (tables, dashboards), annotate reading order, keyboard navigation expectations, and any sticky headers that could obscure focus.", "When using modals, annotate focus management: initial focus location, focus trap behavior, escape-to-close (if allowed), and focus return target when closed.", "When errors occur in multi-step flows, annotate persistence of user input and whether progress is saved; ensure error summary links to fields for long forms.", "When localization is expected, ensure labels and error messages remain concise and avoid relying on text length for layout; annotate truncation behavior.", "When using CAPTCHAs, security challenges, or MFA, annotate accessible alternatives and compatibility with password managers and autofill.", "If an org uses the CVS Web Accessibility Annotation Kit, map requirements to kit components consistently: focus order markers, label/name callouts, error association callouts, landmark/region callouts, and contrast/target-size notes."], source: "Starter KB based on WCAG 2.2 (W3C/WAI) and CVS Health Web Accessibility Annotation Kit guidance. Key references: https://www.w3.org/TR/WCAG22/ ; https://www.w3.org/WAI/standards-guidelines/wcag/new-in-22/ ; https://www.w3.org/WAI/WCAG22/Understanding/ ; https://github.com/cvs-health/annotations", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["accessibility", "wcag-2-2", "a11y", "inclusive-design", "annotation-kit", "keyboard", "focus", "contrast", "forms", "screen-readers"] },
  "business-review": { id: "business-review", title: "Business Review", purpose: "Provide reference knowledge for capturing, reviewing, and applying business context to product and design work: organizational intent (why), goals (OKRs), measures (KPIs), plans (roadmaps), and decision governance. Designed so teams can validate design decisions against strategy and avoid context switching.", scope: "Applies to product/business context used to guide design and development: why statement/vision, strategy pillars, OKRs, KPIs, initiatives, roadmap, risks, assumptions, and decision history. This starter KB defines structure and best practices. It does not contain any org-specific confidential content; those should be added later via private KBs.", definitions: ["### Why Statement (Purpose)", "A concise statement of the organization's reason for existing and the human or customer value it aims to create (distinct from revenue goals).", "### Vision", "A description of the desired future state the organization is working toward; long-term and directional.", "### Strategy", "A set of choices about where to play and how to win, expressed as priorities and tradeoffs, not a list of projects.", "### Strategy Pillar", "A major theme that focuses investment and clarifies priorities (e.g., “Trust & reliability”, “Self-serve growth”).", "### Objective (OKR)", "A qualitative, outcome-oriented goal describing what impact is desired (not a task list). (Google re:Work OKRs) (https://rework.withgoogle.com/intl/en/guides/set-goals-with-okrs/)", "### Key Result (OKR)", "A measurable outcome that indicates progress toward an objective; should be specific and verifiable.", "### KPI", "A metric used to measure performance over time (health of a product or business outcome). KPIs can inform OKRs but are not the same as OKRs.", "### Initiative", "A coordinated set of work that contributes to one or more OKRs; initiatives are how goals are achieved (projects, programs, releases).", "### North Star Metric", "A primary metric that best represents the value delivered to customers (context-dependent); used to align teams on value creation.", "### Assumption", "A belief taken as true for planning that should be validated (e.g., user behavior, market conditions).", "### Risk", "A potential event or condition that could harm outcomes (delivery, adoption, compliance, trust).", "### Decision Log", "A record of key decisions, including context, alternatives, and rationale, to prevent re-litigating and to preserve institutional memory."], rulesConstraints: ["Treat OKRs as outcomes, not task lists; define impact first and allow teams to choose methods. (Google re:Work OKRs) (https://rework.withgoogle.com/intl/en/guides/set-goals-with-okrs/)", "Each Objective should have 2-5 Key Results; each Key Result must be measurable and time-bound.", "Key Results should measure outcomes (behavior, success, quality), not outputs (shipping features) unless an output is the only verifiable proxy.", "Avoid metric overload: identify a small set of decision-driving KPIs and clearly define each metric (formula, data source, cadence).", "Always capture tradeoffs: what will not be done, what will be deprioritized, and why.", "Tie initiatives and roadmap items to objectives and key results; if work cannot be traced to strategy or operational necessity, challenge it.", "Document assumptions explicitly and define validation plans (signals, experiments, research) before large investments.", "Maintain a decision log for major product/design decisions: context, options considered, decision, and rationale.", "Keep strategy artifacts current: include dates, owners, and review cadence; stale strategy is worse than no strategy.", "Privacy and confidentiality: do not store sensitive customer or employee personal data in public/shared business-review KBs; use redaction and private KBs where needed."], doDont: { do: ["Write a crisp Why/Vision statement that is stable and can be used to evaluate decisions.", "Define 3-6 strategy pillars that clearly guide prioritization and tradeoffs.", "Use OKRs to align on outcomes and focus; use initiatives/roadmap to describe the work planned to pursue those outcomes. (Google re:Work OKRs) (https://rework.withgoogle.com/intl/en/guides/set-goals-with-okrs/)", "Define each KPI with a one-line meaning, formula, data source, and owner to prevent metric confusion.", "Create a simple mapping: Pillar → Objective → Key Results → Initiatives → UX/Engineering deliverables.", "Maintain an assumptions list and validate the highest-risk assumptions early (research, prototype tests, experiments).", "Maintain a decision log to reduce churn and preserve rationale; include links to evidence when available.", "Include leading indicators (early signals) and lagging indicators (business outcomes) in measurement plans.", "Use a regular review cadence (monthly/quarterly) to track OKR progress and update priorities."], dont: ["Don't treat OKRs as a backlog or checklist of tasks. (Google re:Work OKRs) (https://rework.withgoogle.com/intl/en/guides/set-goals-with-okrs/)", "Don't use vague objectives (e.g., “Improve UX”) without defining what improvement means and how it will be measured.", "Don't optimize for one metric at the expense of trust, quality, or accessibility; document counter-metrics when needed.", "Don't ship initiatives without a clear link to strategy or to operational requirements (security, compliance, reliability).", "Don't overwrite or delete history; maintain versioning (updatedAt) and keep prior decisions accessible.", "Don't mix confidential org strategy into a public starter KB; keep org-specific content in private KBs with governance."] }, examples: ["### Why statement (example)", "“Help people accomplish complex work with clarity, confidence, and control.”", "### Strategy pillars (example)", "Pillar 1: Time-to-value, Pillar 2: Trust & reliability, Pillar 3: Collaboration, Pillar 4: Self-serve scalability.", "### OKR (good example)", "Objective: “Reduce friction for first-time users completing their first project.” Key Results: “Increase first-project completion rate from 35% to 50%”; “Reduce median time-to-first-success from 12 min to 7 min”; “Reduce onboarding-related support contacts by 20%.” (OKRs as outcomes) (https://rework.withgoogle.com/intl/en/guides/set-goals-with-okrs/)", "### KPI definition (example)", "Activation rate = % of new users who complete the first success action within 7 days. Source: event analytics. Cadence: weekly. Owner: Growth PM.", "### Decision log entry (example)", "Decision: Use a multi-step onboarding flow rather than a single long form. Rationale: reduces cognitive load; supports progressive disclosure; aligns with time-to-value pillar. Evidence: usability sessions (n=8) showed fewer completion errors and higher confidence."], edgeCases: ["Conflicting goals: when an OKR conflicts with a quality/safety constraint (e.g., growth vs trust), define explicit counter-metrics and guardrails.", "Ambiguous ownership: if a KPI or OKR has no clear owner, it will drift; assign owners and review cadence before relying on it.", "Data gaps: if metrics are not instrumented or are unreliable, define temporary proxies and an instrumentation initiative; document uncertainty.", "Multi-product organizations: use a top-level strategy + product-level OKRs; avoid forcing one North Star across unrelated products.", "Volatile markets: treat competitive/trend insights as time-bound; include updatedAt and a refresh cadence; document assumptions that may change.", "Regulated environments: incorporate compliance, accessibility, and security as non-negotiable constraints; reflect them in decision logs and counter-metrics.", "Strategy churn: if leadership changes direction frequently, preserve history via decision logs and explicitly note what changed and why."], source: "Starter KB grounded in widely used strategy and goal-setting frameworks and UX strategy guidance. Key references: Google re:Work OKRs guide; NN/g UX strategy and UX roadmaps; HBR strategy frameworks (e.g., Porter Five Forces; SWOT usage guidance).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["business-strategy", "okrs", "north-star", "kpis", "roadmap", "decision-log", "assumptions", "risks", "stakeholders", "governance"] },
  "competitive-analysis": { id: "competitive-analysis", title: "Competitive Analysis", purpose: "Provide reference knowledge for conducting competitive analysis for product and UX: identifying direct/indirect competitors, benchmarking user experiences, comparing capabilities and positioning, and turning findings into actionable opportunities and design requirements.", scope: "Applies to product and UX competitive work: landscape mapping, feature/experience benchmarking, competitive usability evaluations, positioning analysis, and opportunity identification. Excludes copying competitors blindly, IP-sensitive reverse engineering, and any guidance to implement deceptive/dark patterns (use the Dark & Deceptive Practices KB for detection/remediation only).", definitions: ["### Direct Competitor", "A product that targets the same user segments and solves the same core job with a similar solution category.", "### Indirect Competitor / Substitute", "A different solution category that satisfies the same underlying job (e.g., spreadsheets as a substitute for a workflow tool).", "### Competitive Review", "A fast expert review of competitors' UI/flows to learn patterns, strengths/weaknesses, and design conventions; lower rigor than research.", "### Competitive Research (Competitive Usability Evaluation)", "A structured study comparing products using tasks, participants, and measures to assess relative UX strengths/weaknesses. (NN/g competitive usability evaluations)", "### Benchmark", "A reference comparison point for performance, UX quality, features, or outcomes (e.g., onboarding completion time).", "### Positioning Map", "A map that compares offerings along meaningful dimensions (e.g., price vs benefits) from the customer's perspective. (HBR positioning map)", "### Feature Matrix", "A structured table comparing capabilities across competitors, ideally paired with depth/quality ratings and evidence.", "### UX Teardown", "A step-by-step analysis of a product flow (e.g., sign-up, search, checkout) capturing patterns, copy, IA, friction, and differentiators."], rulesConstraints: ["Start with the user job: define the primary job-to-be-done, key tasks, and success outcomes before comparing products.", "Separate observation from interpretation: record what you see (evidence) distinctly from your conclusions.", "Use comparable tasks and conditions across products (same user intent, same device context) to avoid biased comparisons.", "Do not optimize for feature count alone. Evaluate quality, usability, discoverability, and effectiveness.", "When doing a competitive usability evaluation, use consistent tasks and scoring criteria to compare relative strengths/weaknesses (NN/g competitive usability).", "Triangulate sources: combine UI review with user feedback, public documentation, pricing, and measurable behaviors when available.", "Frame findings as opportunities: identify where users struggle, what competitors do better/worse, and what differentiates meaningfully.", "Avoid “copying”: replicate the underlying principle, not the surface UI. Consider brand, platform guidelines, and your constraints.", "Document assumptions and uncertainty. If you cannot verify a claim (e.g., behind a paywall feature), label it as unknown.", "Update cadence: treat competitive findings as time-bound; include an updatedAt date and consider periodic refresh for key markets."], doDont: { do: ["Define scope upfront: products, segments, platforms (iOS/Android/web), and top 3-7 tasks to compare.", "Create a consistent template for capture: screenshots, flow steps, notes, plus a rubric (e.g., clarity, friction, time, errors).", "Classify competitors: direct, adjacent, substitutes, and “best-in-class” inspirations for specific tasks.", "Compare at the right level: user outcomes and task success first, then patterns and UI components.", "Use a rubric to score experiences (e.g., onboarding clarity, navigation, forms, accessibility, states).", "Assess positioning: who it's for, key promises, pricing model, and what the product emphasizes on landing pages and in-app.", "Identify differentiators and “table stakes” separately to avoid chasing parity features unnecessarily.", "Capture both strengths and weaknesses so design decisions are balanced and grounded."], dont: ["Don't treat competitive analysis as a list of features; assess the user experience quality and business model constraints.", "Don't assume a competitor's implementation is optimal just because it's common; validate with user needs and context.", "Don't include or recommend deceptive/dark patterns; if found, document harm and remediation only.", "Don't ignore accessibility and states (loading, empty, error, permissions) in comparisons; these often differentiate real quality.", "Don't base conclusions on marketing claims alone; verify with product use and evidence when possible.", "Don't overfit to one competitor; use multiple references to avoid biased direction."] }, examples: ["### Competitive UX teardown (example structure)", "Flow: Sign-up → onboarding → first success action. Capture: steps, user questions, friction points, copy patterns, error handling, and time-to-value.", "### Feature matrix (example columns)", "Capability | Competitor A | Competitor B | Our product | Notes/Evidence | Quality (1-5) | User value (H/M/L) | Differentiation (H/M/L).", "### Positioning snapshot (example prompts)", "Target user? Core promise? Proof points? Pricing model? Key objections addressed? What's emphasized in nav and hero content?", "### Opportunity statement (example)", "Competitors reduce onboarding time-to-value by guiding a single primary setup path; opportunity: simplify our onboarding to one clear path with progressive disclosure.", "### Competitive usability evaluation tasks (example)", "Task 1: Find X; Task 2: Configure Y; Task 3: Recover from an error; compare success rate, time, confidence, and reported difficulty across products."], edgeCases: ["Paywalled/enterprise features: document as unknown unless verified; avoid assumptions about capability depth.", "Rapidly changing markets (AI features, pricing): separate stable findings (IA, core flow quality) from volatile ones (feature availability) and refresh more often.", "Platform differences: compare like with like (iOS vs iOS). If one competitor is web-only, note platform constraints explicitly.", "Different target segments: if a competitor targets a different persona, treat it as inspiration rather than direct benchmark; adjust rubrics accordingly.", "Legal/compliance constraints: note where your product must differ due to regulation, privacy, or enterprise requirements.", "Copying risk. When a pattern is valuable, abstract it into principles (reduce steps, clarify hierarchy, improve recovery) rather than replicating UI exactly."], source: "Starter KB compiled from trusted strategy + UX research guidance. Primary references: NN/g competitive usability evaluations and competitive research methods; HBR competitive strategy frameworks (e.g., Porter); Strategyzer value proposition tools; plus web standards for structured comparisons. Example refs: https://www.nngroup.com/articles/competitive-usability-evaluations/ ; https://www.nngroup.com/videos/competitive-reviews-vs-competitive-research/ ; https://hbr.org/2008/01/the-five-competitive-forces-that-shape-strategy ; https://hbr.org/2007/11/mapping-your-competitive-position ; https://www.strategyzer.com/library/the-value-proposition-canvas", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["competitive-analysis", "product-strategy", "ux-research", "benchmarking", "positioning", "feature-matrix", "teardown", "differentiation", "market-landscape"] },
  "content-design": { id: "content-design", title: "Content Design", purpose: "Provide reference knowledge for writing and validating product UI copy (microcopy, labels, helper text, error messages, empty states, and system messaging). Supports consistent, clear, accessible, user-centered content that reduces friction and builds trust.", scope: "Applies to user-facing interface content across web and mobile: labels, buttons, helper text, validation/errors, empty and loading states, confirmations, notifications, and informational guidance. Excludes assistant behavior, tone control, output formatting rules, schema syntax, and runtime tool/DS enforcement.", definitions: ["### Content Design", "Designing the words in an experience to help users accomplish their goals; grounded in user needs, clarity, and accessibility. Content is treated as part of the interface, not a final layer. :contentReference[oaicite:1]{index=1}", "### Microcopy", "Short UI text that guides users through an interaction (e.g., field labels, helper text, error messages, button text). :contentReference[oaicite:2]{index=2}", "### Label", "The primary descriptor for a control or piece of information (e.g., input label, button label). Labels must be clear, specific, and scannable.", "### Helper Text", "Supporting text that clarifies expected input or how information will be used; often shown near a field. Material guidance commonly swaps helper text with error text when needed. :contentReference[oaicite:3]{index=3}", "### Empty State", "A screen or region with no content yet (e.g., zero results, no messages). Should explain why it’s empty and what to do next.", "### Error Message", "A message shown when an error occurs that explains what happened and how to recover; should be visible, constructive, and efficient. :contentReference[oaicite:4]{index=4}"], rulesConstraints: ["Write for user needs and tasks first; content should help users understand and complete what they came to do. :contentReference[oaicite:5]{index=5}", "Use plain language: prefer common words, short sentences, and active voice; avoid internal jargon, acronyms, and legalese unless required. :contentReference[oaicite:6]{index=6}", "Be specific and concrete: reference the object/action (what, where, which) rather than generic statements.", "Optimize for scanning: front-load the most important words (especially in headings, labels, and buttons). :contentReference[oaicite:7]{index=7}", "Prefer recognition over recall: show users what’s needed (formats, examples, constraints) near the point of action.", "Do not blame or shame the user. Use neutral, respectful language (especially for errors). :contentReference[oaicite:8]{index=8}", "Error accessibility: when an input error is detected, identify the item in error and describe it in text; provide suggestions when possible. :contentReference[oaicite:9]{index=9}", "Time errors and validation feedback after interaction when possible (e.g., on blur or submit), not before the user has acted. :contentReference[oaicite:10]{index=10}", "Minimize copy while preserving clarity: remove redundant text; keep helper text only when it reduces errors or increases confidence. :contentReference[oaicite:11]{index=11}", "Maintain consistency in terminology: use one term for the same concept everywhere (UI labels, help, errors, confirmations)."], doDont: { do: ["Use action-led button labels that describe outcomes (e.g., “Save changes”, “Create account”) rather than vague verbs (e.g., “Submit”).", "Use explicit field labels; avoid relying on placeholder text as the only label (placeholders disappear).", "For helper text, explain constraints and intent: format examples, character limits, how data is used (when it reduces uncertainty). :contentReference[oaicite:12]{index=12}", "For errors, include: (1) what went wrong, (2) where it happened, (3) how to fix/recover. :contentReference[oaicite:13]{index=13}", "Use consistent voice and terminology across the product; keep microcopy short and skimmable. :contentReference[oaicite:14]{index=14}", "For empty states, explain why it’s empty and provide a primary next action; if it’s a ‘zero results’ state, suggest how to broaden the query.", "For confirmations, match the level of interruption to the risk (quiet confirmation for safe actions; stronger confirmation for destructive/irreversible actions).", "Make system status clear (saving, syncing, offline, retrying) using concise, user-meaningful language."], dont: ["Don’t use vague messages like “Something went wrong” without actionable next steps. :contentReference[oaicite:15]{index=15}", "Don’t use jargon, stack traces, internal codes, or blameful phrasing in user-facing messages. :contentReference[oaicite:16]{index=16}", "Don’t use double negatives or trick phrasing in consent/opt-out copy (increases mistakes).", "Don’t overuse helper text or tooltips; if many fields need explanation, the form/flow likely needs simplification.", "Don’t hide critical information (fees, consequences, cancellation) behind ambiguous microcopy or low-salience UI (trust and compliance risk).", "Don’t rely on color alone to communicate meaning (errors, warnings, status). :contentReference[oaicite:17]{index=17}"] }, examples: ["### Buttons", "Good: “Save changes” (clear outcome). Poor: “Submit” (ambiguous).", "### Labels and helper text", "Label: “Work email”. Helper: “We’ll use this to send account updates.” (clarifies intent).", "### Validation error (field-level)", "Good: “Enter a valid email address (for example, name@example.com).” (what + how to fix). :contentReference[oaicite:18]{index=18}", "### System error (recoverable)", "Good: “We couldn’t save your changes. Check your connection and try again.” (status + recovery). :contentReference[oaicite:19]{index=19}", "### Empty state (no items yet)", "Good: “No invoices yet. Create an invoice to get paid faster.” Primary action: “Create invoice”.", "### Zero results", "Good: “No results for ‘knee brace’. Try removing filters or searching for a broader term.”"], edgeCases: ["When users are under stress (payments, security, account access), prioritize clarity and recovery over friendliness; keep language calm and direct.", "When multiple errors can occur, show the most important errors first; if feasible, show all field-level errors at once to avoid repeated submit-fail cycles. :contentReference[oaicite:20]{index=20}", "When a system action partially succeeds, clearly distinguish what succeeded vs what failed and what the user must do next (avoid ambiguous mixed states).", "When offline/degraded, acknowledge the state, preserve user input, and clarify whether actions are queued or must be retried.", "When content must include legal/compliance language, present a short plain-language summary first, then provide details via progressive disclosure.", "When localization is expected, avoid idioms, culture-specific metaphors, and humor; keep strings short and structurally simple for translation."], source: "Starter KB compiled from trusted UX writing and accessibility guidance (NN/g, GOV.UK content design guidance, Material Design text-field guidance, WCAG Understanding docs).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["ux-writing", "content-design", "microcopy", "plain-language", "labels", "forms", "empty-states", "error-messages", "accessibility", "product-copy"] },
  "customer-feedback": { id: "customer-feedback", title: "Customer Feedback", purpose: "Provide reference knowledge for turning customer feedback into actionable product and design decisions. Includes collection principles, synthesis methods, insight framing, and prioritization heuristics so teams can validate designs against real user goals and pain points and reduce “papercuts.”", scope: "Applies to collecting, analyzing, and applying customer feedback to UX/product decisions: surveys, in-product feedback, interviews, support tickets, reviews, and usability findings. Includes guidance on synthesis (thematic analysis, affinity mapping), insight statements, JTBD framing, and prioritization. Excludes company-specific customer data; this KB defines how to structure and use feedback, not any proprietary insights.", definitions: ["### Voice of Customer (VoC)", "A programmatic view of customer needs and perceptions derived from multiple feedback channels (in-product feedback, surveys, interviews, support, analytics).", "### Feedback Item", "A single piece of user-reported input (quote, ticket, comment, survey response) that may indicate a need, pain point, bug, or expectation.", "### Theme", "A meaningful pattern across multiple feedback items identified through coding and synthesis (e.g., “confusing pricing,” “can’t find export”). (NN/g thematic analysis) :contentReference[oaicite:1]{index=1}", "### Thematic Analysis", "A systematic approach to organizing qualitative data by tagging observations with codes to discover themes. :contentReference[oaicite:2]{index=2}", "### Affinity Diagramming", "A collaborative method for clustering research findings into groups to reveal patterns and inform decisions. :contentReference[oaicite:3]{index=3}", "### Jobs To Be Done (JTBD)", "A way to describe what users are trying to accomplish (the “job”) and the outcome they want, independent of any specific solution. :contentReference[oaicite:4]{index=4}", "### Insight Statement", "A decision-ready statement that links evidence to a user need and its impact (often: observation + evidence + implication).", "### Signal vs Metric (HEART framing)", "A signal is an observable indicator of success; a metric is how you quantify it (HEART: Happiness, Engagement, Adoption, Retention, Task Success). :contentReference[oaicite:5]{index=5}"], rulesConstraints: ["Collect feedback after meaningful user activity (“task, then ask”); avoid interrupting users before they can form an opinion. :contentReference[oaicite:6]{index=6}", "Treat qualitative feedback as directional, not statistically representative unless sampled appropriately; avoid over-generalizing from a few comments.", "Always preserve evidence: retain the original quote/snippet and context (who/where/when) when creating themes. :contentReference[oaicite:7]{index=7}", "Use a consistent synthesis method (coding → themes → insights → actions). Thematic analysis and affinity mapping are acceptable defaults. :contentReference[oaicite:8]{index=8}", "Separate user needs from proposed solutions: capture what users are trying to do and what blocks them before deciding features.", "Prioritize by impact on task success and frequency, not intensity of wording alone (loud complaints can be outliers).", "When feedback conflicts, document the segments/contexts where each is true; do not average away meaningful differences.", "Convert themes into decision-ready outputs: design requirements, backlog items, experiment hypotheses, or usability acceptance criteria.", "Respect privacy and consent: avoid storing sensitive personal data in design artifacts; redact where needed; minimize collection to what is necessary."], doDont: { do: ["Capture each feedback item with: channel, user segment (if known), task/context, severity, and evidence (quote/snippet).", "Use thematic analysis to code feedback items and identify recurring themes. :contentReference[oaicite:9]{index=9}", "Use affinity diagramming to cluster findings and align teams on patterns. :contentReference[oaicite:10]{index=10}", "Frame insights as: user goal → obstacle/pain → impact → evidence → opportunity.", "Use JTBD-style phrasing to keep needs solution-agnostic (what users want to accomplish and why). :contentReference[oaicite:11]{index=11}", "Tie feedback to design validation checks (e.g., ‘Users can find export in <10s’).", "Quantify where possible: pair themes with a signal/metric (task success, drop-off, ticket volume). :contentReference[oaicite:12]{index=12}", "Close the loop: if you ask for feedback, acknowledge it and share outcomes when feasible (builds trust). :contentReference[oaicite:13]{index=13}"], dont: ["Don’t treat a single anecdote as a universal truth without corroboration.", "Don’t rewrite feedback into a solution prematurely (‘Add feature X’) without clarifying the underlying need.", "Don’t ignore context: the same comment can mean different things in different flows, segments, or devices.", "Don’t mix bugs, usability issues, and feature requests into one bucket; classify them distinctly.", "Don’t prioritize solely by the loudest stakeholder or the most emotional feedback phrasing.", "Don’t store raw sensitive data (account numbers, personal identifiers) in design files or KBs."] }, examples: ["### Feedback item (raw)", "“I keep getting logged out while I’m filling this form.” Channel: support ticket. Context: long form. Device: mobile.", "### Theme (coded)", "Session expiration interrupts long tasks.", "### Insight statement (decision-ready)", "Users attempting long tasks lose progress due to session timeouts, causing frustration and repeat work. Evidence: multiple tickets referencing logout during form completion. Impact: task abandonment and support load.", "### JTBD framing", "Job: “Complete a multi-step form without losing progress.” Outcome: “Finish confidently, even if I’m interrupted.” :contentReference[oaicite:14]{index=14}", "### Validation criterion derived from feedback", "If a session expires mid-form, preserve inputs and provide a re-auth flow that returns users to the same step.", "### Prioritization example", "High priority if: blocks task success (cannot submit), occurs frequently (many tickets), and has high business impact (conversion drop)."], edgeCases: ["Conflicting feedback: segment it (new vs expert users, mobile vs desktop, region, plan tier) and design for the dominant task while providing escape hatches for edge workflows.", "Low-frequency/high-severity issues: prioritize even if rare when the consequence is major (security, payment failures, data loss).", "Feedback driven by misunderstanding: treat as a clarity/usability problem first (labels, affordances, onboarding), not necessarily a feature gap.", "Biased collection channels: support tickets skew toward problems; reviews skew toward extremes; in-product prompts skew toward engaged users. Account for channel bias.", "“Solution requests” from users: translate to the underlying need; keep the request as a candidate solution, not the requirement.", "Regulated/sensitive domains: redact and minimize data; store only what’s needed to make a design decision; document consent boundaries."], source: "Starter KB compiled from trusted UX research and VoC practices (NN/g on user feedback collection + thematic analysis + affinity diagramming; JTBD framing references; HEART metrics framing).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["voice-of-customer", "customer-feedback", "ux-research", "qualitative", "quantitative", "insights", "prioritization", "jobs-to-be-done", "product-discovery"] },
  "dark-deceptive-practices": { id: "dark-deceptive-practices", title: "Dark & Deceptive Practices", purpose: "Reference knowledge for identifying dark and deceptive UX patterns, framing user harm and trust risks, and recommending ethical remediation. For detection and remediation only; not for implementing or encouraging manipulation.", scope: "Applies to identification, risk assessment, and remediation of patterns that pressure, confuse, or harm users. Excludes any instructions on how to design or implement dark patterns, coercive copy recipes, or step-by-step manipulation. Content is for evaluation and ethical alternatives only.", definitions: ["### Forced Action: Requiring users to do something unrelated to their goal (e.g. mandatory account creation to view pricing, bundled consent).", "### Nagging: Repeated prompts that interrupt user flow to influence behavior (e.g. persistent modals, repeated upsells).", "### Obstruction: Making tasks harder than necessary (e.g. hard-to-find cancel, hidden opt-outs, unnecessary steps).", "### Sneaking: Hiding or disguising information (e.g. pre-checked boxes, hidden fees, visual misdirection).", "### Interface Interference: Manipulating visual hierarchy to bias decisions (e.g. dominant Accept vs muted Decline).", "### False Urgency/Scarcity: Fake countdowns, pressure tactics, misleading availability claims.", "### Confirmshaming: Guilt-inducing language for opting out (e.g. 'No thanks, I prefer poor security').", "### Trick Questions: Confusing or misleading wording that causes accidental consent or commitment.", "### Hidden Subscription/Roach Motel: Easy to enter, hard to exit (e.g. one-click signup, buried cancellation).", "### Misleading Defaults: Defaults that benefit the business over the user without clear disclosure (e.g. pre-selected paid options)."], rulesConstraints: ["Evaluate intent and effect, not just visual style. Consider financial harm, loss of autonomy, confusion, and regulatory risk.", "When identifying a pattern, state what was found, why it is deceptive, and what harm or risk it creates.", "Always suggest a remediation: an ethical alternative or fix that preserves user choice and clarity.", "If evidence is insufficient, say so explicitly rather than inferring deception.", "Be specific about what you observe in the design (elements, copy, layout) that supports the finding."], doDont: { do: ["Identify patterns that may pressure, confuse, or harm users.", "Explain why a pattern is deceptive and what user harm or risk it creates.", "Recommend remediation: ethical alternatives, clearer disclosure, or safer defaults.", "Use categories (Forced Action, Nagging, Obstruction, etc.) to classify findings.", "Frame guidance as 'avoid X; replace with Y' for clarity."], dont: ["Provide instructions on how to design or implement dark patterns.", "Include coercive copy recipes or step-by-step instructions to manipulate users.", "Suggest ways to hide opt-outs, obscure pricing, or create false urgency.", "Encourage any pattern that undermines informed consent or user autonomy."] }, examples: ["### Good finding: 'Pricing is hidden behind mandatory account creation (Forced Action). Remediation: Allow pricing view without account; optional sign-up after intent is clear.'", "### Good remediation: 'Replace pre-checked newsletter signup with unchecked box and clear label (avoid Sneaking).'", "### Risk framing: 'Dominant Accept vs muted Decline button (Interface Interference) can lead to consent without meaningful choice; recommend equal visual weight for both options.'"], edgeCases: ["When a pattern could be legitimate (e.g. limited-time offer that is real), note uncertainty and recommend clear disclosure.", "When cultural or context norms affect perception (e.g. aggressive upsell in some markets), frame harm in terms of informed choice and clarity.", "When the design is ambiguous, describe what was observed and what would make it clearly ethical or clearly deceptive."], updatedAt: "2026-01-21T14:00:00.000Z", version: "1.0", tags: ["dark-patterns", "deceptive-ux", "ethics", "remediation", "user-harm"] },
  "design-critique": { id: "design-critique", title: "Design Critique", purpose: "Reference knowledge for evaluating UI and UX quality: critique heuristics, evaluation dimensions, scoring guidance, and review checklists. Supports consistent, actionable design feedback.", scope: "Applies to design review and critique: usability, clarity, information architecture, visual hierarchy, accessibility, composition, and content quality. Excludes output format enforcement, schema syntax, and tool/DS rules.", definitions: ["### Hierarchy and focus: The degree to which the most important information or action is immediately clear. Primary actions and key content should dominate; secondary elements should support without competing.", "### Layout and alignment: Intentional structure and alignment of elements. Consistent grids and alignment create order and reduce cognitive load.", "### Spacing and proximity: Related elements grouped clearly; unrelated elements separated. Use spacing to signal relationships and create rhythm.", "### Affordance: The quality of suggesting how an element can be used. Buttons should look clickable; inputs should invite entry; links distinguishable.", "### Consistency: Reuse of components, styles, and spacing patterns. Reduces learning effort and builds trust."], rulesConstraints: ["Base scores on overall usability impact, not visual polish alone. Consider clarity, hierarchy, and friction.", "Wins must be specific and tied to dimensions (e.g. hierarchy, spacing). Avoid vague praise.", "Fixes must be specific (values, measurements, references), actionable in Figma, and ordered by impact.", "Checklist items should be reusable validation steps the user can apply to future designs.", "Evaluate: Hierarchy, Layout, Spacing, Typography, Color/Contrast, Affordance, Consistency, Accessibility, States (hover, focus, disabled, error, loading).", "Scoring guidance: 90–100 exceptional; 80–89 strong; 70–79 solid; 60–69 functional; below 60 major issues."], doDont: { do: ["Tie wins to specific dimensions (hierarchy, spacing, clarity).", "Give concrete fixes (e.g. 'Add 16px padding between sections', 'Increase contrast to meet WCAG AA').", "Order fixes by impact (most critical first).", "Reference specific elements by name or type when context is available.", "Consider accessibility: contrast, legibility, hit targets, states."], dont: ["Use vague advice such as 'Clean this up' or 'Improve hierarchy' without specifics.", "Praise vaguely (e.g. 'Looks good').", "Omit actionable guidance (e.g. suggest 'fix spacing' without saying how much or where).", "Ignore states (disabled, error, loading) when they are relevant."] }, examples: ["### Good win: 'Primary CTA is visually dominant and clearly separated from secondary actions.'", "### Good fix: 'Increase text contrast for body text to meet WCAG AA (currently #666, suggest #333).'", "### Good checklist item: 'Primary action is visually dominant.'", "### Poor fix: 'Improve spacing.' (Prefer: 'Add 8px spacing between related form fields.')"], edgeCases: ["When selection context is missing, recommend selecting one or more design elements before critiquing.", "When the design is minimal (e.g. wireframe), focus on structure and hierarchy rather than polish.", "When multiple screens or flows are in view, clarify which area the critique addresses or provide a per-area summary."], updatedAt: "2026-01-21T14:00:00.000Z", version: "1.0", tags: ["ux", "design-review", "usability", "accessibility", "visual-hierarchy"] },
  "design-heuristics": { id: "design-heuristics", title: "Design Heuristics", purpose: "Provide reference knowledge for evaluating and improving UI/UX quality using established heuristics and standards. Intended for design critique, QA reviews, discovery, and inspiration across product, design, engineering, and content workflows.", scope: "Applies to user-facing interfaces across web and mobile: interaction design, layout, navigation, forms, feedback, states, accessibility, and content clarity. Excludes assistant behavior, tone control, output formatting, JSON/schema enforcement, and runtime execution rules.", definitions: ["### Usability Heuristic", "A general design principle used to evaluate interface usability and identify likely issues (especially effective for quick expert reviews).", "### Nielsen’s 10 Usability Heuristics", "A widely used set of 10 principles for interface design evaluation (e.g., visibility of system status, consistency and standards, error prevention).", "### ISO 9241-110 Interaction (Dialogue) Principles", "International standard principles describing qualities of usable interactive systems (e.g., suitability for the task, self-descriptiveness, controllability, conformity with user expectations).", "### WCAG (POUR)", "Accessibility principles: Perceivable, Operable, Understandable, Robust; used to evaluate whether experiences work for people with disabilities and assistive tech."], rulesConstraints: ["Prefer evidence-based critique: tie findings to observed UI elements, user goals, and a specific heuristic or principle.", "Prioritize by user impact and frequency: address blockers (task failure), then high-friction issues, then polish.", "Recommend fixes as concrete design changes (what to change, where, and how), not vague advice.", "Always evaluate key states where applicable: empty, loading, error, success, disabled, focus, hover, offline, and partial success.", "Assume constraints: optimize for clarity and recoverability rather than perfect completeness when context is limited.", "Accessibility baseline: evaluate against WCAG principles and common AA expectations (e.g., contrast, keyboard, focus visibility, labels).", "Avoid conflicting guidance: when two heuristics trade off (e.g., minimalist design vs discoverability), choose the option that best supports the user’s task and reduces critical errors."], doDont: { do: ["Map each finding to a heuristic (Nielsen/ISO/WCAG) to make critiques consistent and teachable.", "Check navigation and wayfinding: users should always know where they are, what happened, and what to do next.", "Check recognition over recall: reduce memory load with visible options, previews, defaults, and sensible constraints.", "Check control and freedom: provide undo/back/cancel, safe exits, and reversible actions for risky steps.", "Check consistency: patterns, components, spacing, terminology, and behaviors should match within the product and platform conventions.", "Check feedback loops: show system status, progress, and confirmations promptly and proportionately.", "Check error prevention + recovery: prevent mistakes; when failures happen, explain what happened and how to recover.", "Check accessibility early: labels, focus order, keyboard access, contrast, and error announcement patterns."], dont: ["Don’t give generic feedback like “improve hierarchy” without pointing to specific elements and changes.", "Don’t optimize aesthetics at the expense of comprehension, task success, and accessibility.", "Don’t hide critical actions, costs, or consequences behind ambiguous UI or copy.", "Don’t require users to remember information between steps when it can be shown or inferred.", "Don’t rely on color alone to communicate meaning (errors, selected states, statuses).", "Don’t introduce new interaction patterns without a clear user benefit and consistent application."] }, examples: ["### Example: Visibility of system status (Nielsen)", "Finding: A Save action provides no feedback; users are unsure if it worked. Fix: Add inline ‘Saved’ confirmation and/or a toast; for long operations show progress and disable repeated submission.", "### Example: Recognition rather than recall (Nielsen)", "Finding: Users must remember filter criteria after navigating back. Fix: Persist filter chips and show active filters above results with clear reset controls.", "### Example: Controllability + undo (ISO / Nielsen User control & freedom)", "Finding: Deleting an item is immediate with no undo. Fix: Provide an undo snackbar/toast for a short window; for destructive actions require confirmation with clear consequences.", "### Example: WCAG Understandable", "Finding: Form errors are only shown in a red banner at top; screen reader users don’t hear field-level guidance. Fix: Add field-level messages bound to inputs, focus the first invalid field on submit, and ensure errors are announced."], edgeCases: ["When selection context is missing, provide general heuristics and ask for the specific screen, flow, or element to evaluate.", "When reviewing a single component inside a larger screen, evaluate local usability first, then note likely upstream/downstream dependencies (validation, empty states, permissions).", "When designs are wireframes, prioritize structure, flow, and clarity over visual polish.", "When there is a trade-off between speed and safety (e.g., confirmation dialogs), choose the least-friction option that still prevents high-impact errors (undo often beats confirmation).", "When platform conventions differ (iOS vs Android vs web), prefer the target platform’s norms for navigation patterns, affordances, and system feedback."], source: "Compiled from widely used UX heuristics and standards (NN/g heuristics; ISO 9241-110 interaction principles; WCAG 2.2; Material Design usability/accessibility guidance).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["ux", "ui", "heuristics", "usability", "design-review", "accessibility", "information-architecture", "interaction-design"] },
  "design-system-nuxt-ui": { id: "design-system-nuxt-ui", title: "Design System: Nuxt UI (v4)", purpose: "Reference knowledge for using the Nuxt UI v4 design system in design reviews and canvas mutation: component intent, semantic color usage, token-first theming, and consistent states (success, warning, error, disabled, loading). Intended to be paired with a Nuxt UI Figma kit/library and extended with component keys and org-specific rules.", scope: "Applies to (1) design evaluation: validate that designs use Nuxt UI patterns, semantic colors, and states consistently; (2) design generation: guide selection of Nuxt UI components and tokens when producing screens; (3) theming: ensure token/variable-driven theming supports light/dark. Excludes assistant behavior, output formatting rules, and any project-specific implementation constraints unless provided separately. This KB does not include component keys; add them from the Nuxt UI Figma kit/library when available.", definitions: ["### Design tokens (Tailwind v4 @theme)", "Nuxt UI uses Tailwind CSS v4 token customization via the @theme directive in CSS. Tokens can define fonts, colors, breakpoints, and other theme variables. (Nuxt UI design system docs)", "### Semantic colors", "A semantic color names intent/purpose rather than a specific value. Nuxt UI defines semantic aliases like primary, secondary, success, info, warning, error, neutral. These map to Tailwind palette colors or custom colors defined in @theme. (Nuxt UI design system docs)", "### CSS variables as tokens", "Nuxt UI uses CSS variables as design tokens to support consistent theming with built-in light and dark mode behavior. (Nuxt UI CSS variables docs)", "### Utility classes for semantic colors", "Nuxt UI provides utility classes like text-error and bg-success, backed by CSS variables (for light/dark). (Nuxt UI CSS variables docs)", "### Runtime color configuration", "Nuxt UI allows mapping semantic colors (e.g., primary, secondary, neutral) to theme colors at runtime via ui.colors (app.config.ts) and equivalent Vite config. (Nuxt UI design system docs)", "### Component props for semantic color", "Many Nuxt UI components expose a color prop that maps to semantic colors (e.g., UButton color=\"primary\"). (Nuxt UI design system docs; Button docs)", "### Nuxt UI Figma kit", "Nuxt UI provides an official Figma design kit with components, variants, and local variables/tokens designed to match development props and tokens. (Nuxt UI Figma page)", "### Form validation events", "Nuxt UI Form triggers validation when inputs emit input, change, or blur, and always validates on submit; validate-on controls timing. (Form component docs)"], rulesConstraints: ["Prefer semantic colors over hard-coded values: use primary/secondary/success/info/warning/error/neutral to express intent. (Nuxt UI design system docs)", "If defining custom colors via Tailwind theme variables, define the full shade range 50 through 950 for each color. (Nuxt UI design system docs)", "Only map semantic colors to colors that exist in the theme (Tailwind default palette or custom colors defined via @theme). (Nuxt UI design system docs)", "Nuxt UI semantic color utilities (e.g., text-primary, bg-error) are implemented via CSS variables that change between light and dark. Designs should validate both modes. (Nuxt UI CSS variables docs)", "If a semantic color needs to be solid black/white, set it directly via CSS variables (not via a named palette color lacking shades). (Nuxt UI CSS variables docs)", "Use component-level color props when supported (e.g., UButton color) to align design and development semantics. (Nuxt UI design system docs; Button docs)", "For forms, expect validation to run on input/change/blur depending on validate-on and always on submit. Designs should include corresponding error messaging and states. (Form docs)", "Modal content should be structured via slots (content, header/body/footer patterns). Designs should account for focus and dismiss behavior. (Modal docs)", "Toast patterns may include actions; designs should reserve space for action affordances and avoid critical flows that rely solely on transient toasts. (Toast docs)", "When using the Nuxt UI Figma kit, prefer using its variables/tokens rather than overriding styles per-instance; token edits should propagate across the system. (Nuxt UI Figma page)", "If the Nuxt UI library is unavailable in a file, fall back to primitives but keep semantic intent (component intent + token roles). This is required for resilient canvas mutation."], doDont: { do: ["Use semantic colors to communicate meaning (error for validation/destructive, warning for attention, success for confirmation, neutral for backgrounds/borders). (Nuxt UI design system docs)", "Validate designs in both light and dark modes because Nuxt UI swaps semantic variable shades between modes. (Nuxt UI CSS variables docs)", "Use component variants and props consistently with the system (e.g., Button as primary action; secondary actions use secondary/neutral and appropriate variant). (Button docs; design system docs)", "For forms, show error states aligned to when validation occurs (input/change/blur/submit) and avoid surprising early error spam. (Form docs)", "When generating designs from specs, prefer Nuxt UI components from the Figma kit and apply tokens via variables so global theming works. (Nuxt UI Figma page)", "Document mapping from semantic intent to component choices (e.g., primary CTA -> Button primary; destructive -> Button color=error) to keep reviews consistent."], dont: ["Do not hard-code hex colors for semantic meaning when Nuxt UI semantic colors exist (unless explicitly required by a brand constraint). (Nuxt UI design system docs)", "Do not define partial custom palettes (missing shades). Nuxt UI expects complete shade sets for custom colors. (Nuxt UI design system docs)", "Do not map semantic colors to palette names that do not support multiple shades when configuration requires shades; use CSS variable direct assignment for solid black/white. (Nuxt UI CSS variables docs)", "Do not rely on a single global error message when field-level errors are possible; align to validation triggers and provide recoverable guidance. (Form docs + general UX best practice)", "Do not design critical confirmations only as toasts with no persistent acknowledgement when users may miss transient feedback. (Toast docs + general UX best practice)"] }, examples: ["### Semantic color usage (design intent)", "Use error for validation and destructive actions, warning for attention-needed states, success for confirmation states, and neutral for non-emphasis UI. (Nuxt UI design system docs)", "### Component color prop (Button)", "Use semantic mapping for CTAs such as UButton color=\"primary\" for main actions and error/warning where supported for destructive/attention states. (Nuxt UI design system docs; Button docs)", "### Form validation timing", "If validate-on includes blur, show field-level error after focus leaves the input; always validate on submit and show unresolved errors together. (Form docs)", "### Modal structure", "Modal should have a clear trigger, and content should be placed in a dedicated content slot; header/body/footer sections can be used for consistent layout. (Modal docs)", "### Toast actions", "Toasts can include actions (e.g., Undo). If included, design the toast to accommodate a button action without truncation. (Toast docs)", "### Token-first theming in Figma", "When using the Nuxt UI Figma kit, update local variables/tokens to theme the system rather than overriding local instances. (Nuxt UI Figma page)"], edgeCases: ["### Missing Nuxt UI library access", "If the Figma library is not enabled or not accessible, fall back to primitives while preserving semantic intent (component type + semantic color roles). Provide a user hint to enable the Nuxt UI library for full fidelity.", "### Custom palette gaps", "Custom colors must include all shades 50-950; missing shades can break consistent theming and semantic mappings. (Nuxt UI design system docs)", "### Solid black/white as primary", "Semantic mapping to black/white should be done via direct CSS variable assignment (not via a palette name without shades). (Nuxt UI CSS variables docs)", "### Validation noise", "If validation is configured to run on input, error copy may appear while the user is typing; prefer blur/submit for many inputs unless inline constraints are essential. (Form docs)", "### Dark mode contrast", "Because semantic variables can map to different shades in dark mode, validate contrast and readability in both modes. (Nuxt UI CSS variables docs)", "### Component key mapping (required for automation)", "To instantiate components via plugin automation from a shared library, you must capture the published component or component set keys from the Nuxt UI Figma kit/library. Node IDs are not portable across files; keys are used for importing components in plugins."], source: "Primary refs: Nuxt UI docs on design system (Tailwind v4 tokens, semantic colors, runtime config), CSS variables (semantic color utilities + light/dark), and component docs (Button, Input, Form validation events, Modal, Toast), plus Nuxt UI Figma kit page. https://ui.nuxt.com/docs/getting-started/theme/design-system ; https://ui.nuxt.com/docs/getting-started/theme/css-variables ; https://ui.nuxt.com/docs/components ; https://ui.nuxt.com/docs/components/button ; https://ui.nuxt.com/docs/components/input ; https://ui.nuxt.com/docs/components/form ; https://ui.nuxt.com/docs/components/modal ; https://ui.nuxt.com/docs/components/toast ; https://ui.nuxt.com/figma", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["design-system", "nuxt-ui", "tailwindcss", "tokens", "semantic-colors", "variables", "components", "figma-library", "theming", "light-dark"] },
  "design-workshop": { id: "design-workshop", title: "Design Workshop", purpose: "Reference knowledge for generating screen layouts and UI blocks (headings, buttons, inputs, cards, etc.) from user descriptions. Supports consistent fidelity, block semantics, and layout guidance.", scope: "Applies to screen layout design, block types, fidelity levels, and styling guidance. Excludes output format enforcement, schema syntax, and runtime execution rules.", definitions: ["### Wireframe fidelity: Grayscale, simple placeholders, minimal typography, no shadows or rounded corners. Best for structure and flow.", "### Medium fidelity: Basic colors, clear hierarchy, subtle borders, light shadows, basic rounded corners. Good default for most screens.", "### Hi fidelity: Full colors, rich typography, refined borders, layered shadows, generous rounded corners. For polished, production-like screens.", "### Creative fidelity: Bold colors, experimental typography, large rounded corners, dramatic shadows. For playful or marketing-style screens.", "### Block (screen block): A single UI element in a screen layout: heading, bodyText, button, input, card, spacer, or image placeholder.", "### Layout: Screen structure (direction vertical/horizontal, padding, gap). Use vertical for most mobile screens; horizontal for toolbars or rows."], rulesConstraints: ["Generate 1-5 screens per request. If the user asks for more, generate up to 5 and note truncation.", "Map the user's app type and tone to screen names and content (e.g. fitness app → fitness-related screens).", "Use fidelity to drive visual style: wireframe = grayscale; medium = basic color; hi = refined; creative = bold.", "Use layout direction and spacing to reflect density (compact vs spacious) when the user requests it.", "Preserve clear visual hierarchy: headings before body text; primary actions before secondary.", "Match user tone: playful/serious/calm should influence colors, corners, and density."], doDont: { do: ["Use clear hierarchy and consistent spacing within and between screens.", "Match fidelity to the user's request (wireframe, medium, hi, creative).", "Use semantic block types: heading for titles, bodyText for paragraphs, button for actions.", "Apply user-mentioned colors as primary or accent where appropriate.", "Name screens meaningfully (e.g. Home, Onboarding, Settings)."], dont: ["Exceed 5 screens in a single response; truncate and note if the user asked for more.", "Ignore user tone or color hints when generating screens.", "Mix fidelities within one screen set; keep fidelity consistent per request.", "Use bodyText for headings or buttons; use the correct block type.", "Omit layout (direction, padding, gap) for screens; use sensible defaults if not specified."] }, examples: ["### Wireframe: Use grayscale fills, simple rectangles for images, minimal text styling.", "### Medium fidelity: Use a restrained palette, 8–12px rounded corners, light drop shadows on cards and buttons.", "### Good screen set: 2–3 screens with clear names (e.g. Login, Home) and blocks that match the requested app type."], edgeCases: ["When the user asks for many screens, generate up to 5 and include a truncation notice.", "When the user does not specify fidelity, default to medium.", "When the user mentions colors but not placement, use the first as primary and optional second as accent.", "When the user asks for both mobile and desktop, prefer one device per run or clarify in meta."], updatedAt: "2026-01-21T12:00:00.000Z", version: "1.0", tags: ["screens", "layout", "wireframe", "fidelity", "ui-blocks"] },
  "errors": { id: "errors", title: "Errors", purpose: "Provide authoritative reference knowledge for designing, evaluating, and validating UX error handling, including error messages, validation feedback, recovery guidance, and failure states.", scope: "Applies to user-facing error handling in interfaces, including form validation, system failures, permission errors, and invalid states.   Excludes assistant behavior, tone control, output formatting, and runtime execution rules.", definitions: ["### Validation Error", "An error caused by invalid, missing, or improperly formatted user input, such as incorrect email formats or required fields left empty.", "### System Error", "An error caused by system-level failures such as network issues, server errors, timeouts, or unexpected crashes.", "### Permission Error", "An error caused by insufficient authorization or access rights, including expired sessions or restricted actions.", "### State Error", "An error caused by an invalid or unexpected application state, such as performing actions out of sequence or with incomplete data."], rulesConstraints: ["Error messages must clearly explain what went wrong.", "Error messages must provide guidance on how the user can recover or resolve the issue.", "Error messages must not blame, shame, or judge the user.", "Errors should be specific and reference the exact field, action, or condition involved whenever possible.", "Errors must remain visible until the issue is resolved.", "User input must be preserved after an error occurs.", "Errors must be accessible and perceivable by assistive technologies.", "Color must not be the sole indicator of an error state.", "System errors must avoid exposing internal technical details unless useful to the user."], doDont: { do: ["Explain the problem clearly and concisely.", "Show errors near the relevant UI element or field.", "Provide actionable recovery steps.", "Preserve user input after errors.", "Indicate whether retrying an action is possible.", "Ensure error messages are accessible and readable."], dont: ["Use vague or generic error messages.", "Blame or shame the user.", "Expose stack traces or internal error codes unnecessarily.", "Clear user input after an error.", "Rely on color alone to indicate errors.", "Use global error messages when a local one is possible."] }, examples: ["### Good Validation Error", "“Email address is invalid. Enter a valid email address (e.g., name@example.com).”", "### Poor Validation Error", "“Something went wrong.”", "### Good System Error", "“We couldn’t save your changes due to a network issue. Please try again.”"], edgeCases: ["Partial success states where some user actions complete successfully while others fail.", "Offline or degraded network conditions that prevent immediate error recovery.", "Retry exhaustion scenarios where repeated attempts continue to fail.", "Irrecoverable system failures that require escalation to support or alternative workflows."], updatedAt: "2026-02-07T03:16:38.573Z", version: "1.0", tags: ["ux", "errors", "error-messages", "validation", "usability"] },
  "forms-input-patterns": { id: "forms-input-patterns", title: "Forms & Input Patterns", purpose: "Provide reference knowledge for designing and evaluating forms and data-entry experiences: field structure, labeling, input selection, progressive disclosure, mobile-friendly entry, and accessibility fundamentals. Intended to reduce friction, prevent mistakes, and improve completion rates.", scope: "Applies to user-facing form and input experiences across web and mobile: field layout, labels, helper text, required/optional signaling, input types, formatting, grouping, multi-step forms, review/confirm steps, and assistive-technology compatibility. Excludes general error-state patterns beyond forms (covered by the Errors KB) and excludes assistant behavior, output formatting rules, schema enforcement, and runtime tool/DS rules.", definitions: ["### Form", "A structured interaction where users enter or confirm information to complete a task (e.g., sign up, checkout, profile update).", "### Field Label", "Persistent text that identifies what data is expected for an input. Labels should be visible in most cases and located close to the field.", "### Helper / Hint Text", "Supporting guidance that clarifies what to enter or how the data will be used; should be used only when it reduces confusion or errors.", "### Placeholder", "Optional in-field hint text. Placeholders are not a substitute for labels and may reduce usability/accessibility when used as the only cue.", "### Progressive Disclosure", "Revealing complexity only when needed (e.g., show additional fields after a selection) to reduce cognitive load.", "### Autofill", "Browser/OS capability that pre-fills known user data (e.g., name, address). Good form design supports autofill and avoids breaking it."], rulesConstraints: ["Every input must have a clear label or instructions identifying what data is expected; ensure each option in radios/checkboxes has an appropriate label.", "Prefer visible, persistent labels; do not rely on placeholder-only labels.", "Place labels close to the fields they describe; avoid ambiguous spacing where a label could map to multiple fields.", "Group related fields visually and conceptually (sections, headings, spacing) to reduce cognitive load.", "Signal required vs optional clearly and consistently (e.g., mark required fields; do not force users to infer).", "Choose the simplest input that satisfies the requirement (e.g., short list -> radio; long list -> select/autocomplete; free text only when needed).", "Minimize typing: use defaults, smart suggestions, autofill, and constrained inputs where appropriate.", "Mobile entry: use appropriate input modes/keyboards (email, numeric) and avoid patterns that cause invalid entry (e.g., numeric spinners for non-quantities).", "Avoid unnecessary validation complexity (overly strict formats) when you can accept flexible input and normalize it.", "For sensitive fields (passwords, payment), prioritize clarity, trust signals, and compatibility with password managers; avoid designs that block paste or autofill without a strong reason."], doDont: { do: ["Use clear, specific labels written in plain language and aligned consistently (often above inputs for mobile and shorter forms).", "Group fields into meaningful sections with short headings (e.g., \"Billing address\", \"Payment details\").", "Ask only what you need; remove non-essential fields or make them optional.", "Use helper text when users commonly make mistakes or need context (format examples, what the data is used for).", "Prefer selection controls over free text when the set of valid answers is known and small.", "Support autofill: keep predictable field names and avoid splitting fields in ways that break autofill (unless necessary).", "Support copy/paste and password managers for credentials; allow show/hide password.", "Use input constraints that match real-world behavior (accept spaces/dashes in phone numbers; accept uppercase/lowercase emails; normalize where feasible).", "Make the primary action clear (\"Continue\", \"Save changes\") and match it to a clear step boundary.", "For multi-step flows, show progress and allow back navigation without losing entered data."], dont: ["Don't use placeholder text as the only label or rely on disappearing hints.", "Don't scatter labels far from inputs or use ambiguous alignment.", "Don't ask for information you don't need at that point in the flow.", "Don't force users into repeated submit-fail cycles; design to prevent mistakes up front (constraints, examples, defaults).", "Don't use dropdowns for short, common choices (radios are faster and more visible).", "Don't require users to remember information from previous steps if you can show it or summarize it.", "Don't break autofill/password managers with unusual field structures or blocking paste without a strong justification.", "Don't use numeric steppers/spinners for things that are identifiers (phone, ZIP, credit card)."] }, examples: ["### Label + hint (good)", "Label: \"Phone number\"  Hint: \"Include country code if outside the US (for example, +44 20 1234 5678).\"", "### Required fields (good)", "Use a consistent required indicator and explain it once (e.g., \"* Required\"). Mark required fields rather than only optional fields.", "### Input choice (good)", "For 2–6 mutually exclusive choices: use radio buttons (visible options). For a long list: use autocomplete with search.", "### Address entry (good)", "Use separate fields for address line 1/2, city, state/region, postal code; support autofill; allow optional address line 2.", "### Password entry (good)", "Label: \"Password\"  Helper: \"At least 12 characters.\" Provide show/hide toggle and allow paste; avoid overly complex rules unless required."], edgeCases: ["When the user is entering identifiers (account numbers, phone, card), avoid controls that imply arithmetic (steppers) and allow common formatting characters (spaces/dashes) where possible.", "When a form is long, prefer multi-step with clear grouping and a review step; preserve data across steps and allow back without loss.", "When information is conditional (e.g., shipping different from billing), use progressive disclosure with clear toggles and preserve hidden-field values appropriately.", "When the design uses custom components (custom select/date picker), define keyboard interaction and focus behavior explicitly and ensure accessible labeling.", "When localization is expected, keep labels short, avoid idioms, and ensure layout can expand for longer translated strings.", "When collecting sensitive data, add trust cues and transparent explanations (why needed, how used), and avoid dark-pattern phrasing or unnecessary collection."], source: "Starter KB compiled from trusted UX and accessibility guidance (NN/g form usability + required fields + placeholders; GOV.UK Design System form components; WCAG 2.2 Understanding: Labels or Instructions; Material text-field guidance).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["ux", "forms", "input-patterns", "ui", "interaction-design", "usability", "accessibility", "mobile", "autofill"] },
  "interaction-patterns-states": { id: "interaction-patterns-states", title: "Interaction Patterns & States", purpose: "Provide reference knowledge for designing and validating common interaction patterns and UI states (loading, empty, success, failure, partial success, permissions, offline). Helps teams choose the right feedback pattern, reduce user uncertainty, and improve recoverability and accessibility.", scope: "Applies to user-facing interfaces across web and mobile: feedback, progress, notifications, dialogs, inline messaging, and state coverage for screens/components/flows. Excludes assistant behavior, tone control, output formatting rules, schema enforcement, and runtime tool/DS rules.", definitions: ["### UI State", "A distinct condition of a screen or component that affects what users see and can do (e.g., loading, empty, error, success, disabled).", "### Loading State", "A state where content or an operation is in progress; must communicate that the system is working and what the user should expect. :contentReference[oaicite:1]{index=1}", "### Determinate Progress", "A progress indicator that shows measurable completion (e.g., progress bar with percent). Use when duration or completion can be estimated. :contentReference[oaicite:2]{index=2}", "### Indeterminate Progress", "A progress indicator that shows activity without a completion estimate (e.g., spinner). Use when time is unknown but the system is working. :contentReference[oaicite:3]{index=3}", "### Skeleton State", "A placeholder UI that approximates the final layout while content loads, improving perceived performance and reducing layout shift.", "### Empty State", "A screen/region with no data to show (first use, deleted content, unavailable content). Should explain what’s happening and provide a next step. :contentReference[oaicite:4]{index=4}", "### Zero Results State", "A special empty state triggered by a query/filter returning no matches; should suggest how to broaden or change the query.", "### Error State", "A state indicating failure (validation, network, server, permission, conflict). Must support recovery when possible. :contentReference[oaicite:5]{index=5}", "### Success State", "A state that confirms an action completed and indicates what changed (saved, submitted, sent).", "### Status Message", "An update about success/results, waiting state, progress, or errors that should be programmatically available to assistive tech without forcing a context change. :contentReference[oaicite:6]{index=6}", "### Snackbar / Toast", "A transient message used for brief feedback that doesn’t block the user; may include a simple action (e.g., Undo). :contentReference[oaicite:7]{index=7}", "### Dialog", "A blocking overlay requiring user attention/decision; use for critical confirmations, destructive actions, or complex decisions. :contentReference[oaicite:8]{index=8}"], rulesConstraints: ["Always cover core states for key screens/flows: default/content, loading, empty/zero, error, success/confirmation, disabled, and offline/degraded where relevant.", "Use feedback to reduce uncertainty: users should know what is happening, whether their action worked, and what to do next. :contentReference[oaicite:9]{index=9}", "Choose the least disruptive pattern that still prevents harm: prefer inline feedback or snackbar over modal dialogs unless the decision is high-risk. :contentReference[oaicite:10]{index=10}", "Loading: show an indicator quickly when the user might perceive a stall; use skeletons when content layout is known and load time is noticeable. :contentReference[oaicite:11]{index=11}", "Use determinate progress when you can estimate completion; otherwise use indeterminate activity indicators. :contentReference[oaicite:12]{index=12}", "Empty states should (1) explain why it’s empty, (2) provide learning cues when appropriate, and (3) offer a clear next step. :contentReference[oaicite:13]{index=13}", "Error states: if recovery is possible, provide a user action (retry, fix input, change filters); do not clear user input on failure. :contentReference[oaicite:14]{index=14}", "For transient notifications, ensure critical information is not lost: persist when necessary or provide a durable history/log for important events.", "Accessibility: ensure status messages (success, saving, loading, errors) are available to assistive technologies without forcing focus changes; do not rely on color alone. :contentReference[oaicite:15]{index=15}", "Interaction states must be distinguishable (enabled, disabled, hover, focus, pressed) and consistent across components. :contentReference[oaicite:16]{index=16}"], doDont: { do: ["Use inline messaging for field-level or component-level issues; use page-level messaging for global failures affecting the whole screen.", "Use snackbars/toasts for lightweight confirmations and reversible actions (e.g., Undo). :contentReference[oaicite:17]{index=17}", "Use dialogs for destructive/irreversible actions or complex decisions that require explicit confirmation. :contentReference[oaicite:18]{index=18}", "Provide clear success feedback for important actions (save, submit, send) and clarify what changed.", "For empty-first-run experiences, provide a primary CTA to create/add/import and a brief explanation of value. :contentReference[oaicite:19]{index=19}", "For zero results, suggest adjustments (remove filters, broaden search, check spelling).", "Preserve user context on failures: keep form inputs, selections, and scroll position when reasonable.", "Design partial success explicitly: show what completed, what failed, and what to do next.", "Use consistent visual state patterns for interactive components (hover, focus, pressed, disabled). :contentReference[oaicite:20]{index=20}", "Ensure status messages and confirmations are accessible (screen-reader discoverable) and not color-only. :contentReference[oaicite:21]{index=21}"], dont: ["Don’t show blocking dialogs for low-risk confirmations (creates interruption and habituation). :contentReference[oaicite:22]{index=22}", "Don’t use spinners for long, predictable operations when a determinate indicator is possible. :contentReference[oaicite:23]{index=23}", "Don’t use empty states as dead ends (blank with no explanation or next step). :contentReference[oaicite:24]{index=24}", "Don’t hide errors behind generic messages without recovery guidance. :contentReference[oaicite:25]{index=25}", "Don’t clear user-entered data after an error unless the user explicitly resets it.", "Don’t rely on color alone to indicate selection, errors, or status. :contentReference[oaicite:26]{index=26}", "Don’t make critical status changes ephemeral with no way to find them again (e.g., disappearing toast for a failed payment)."] }, examples: ["### Loading (content fetch)", "If a feed takes > ~1s: show skeleton rows matching the final layout. If the duration is unknown: show an indeterminate spinner with brief text like “Loading results…”. :contentReference[oaicite:27]{index=27}", "### Saving (background)", "Inline status near the control: “Saving…” then “Saved”. Avoid blocking the user unless there is a conflict risk. :contentReference[oaicite:28]{index=28}", "### Success (reversible action)", "After deleting an item: snackbar “Item deleted” + action “Undo”. :contentReference[oaicite:29]{index=29}", "### Error (recoverable network)", "Inline banner: “We couldn’t load your dashboard. Check your connection and try again.” Button: “Retry”. :contentReference[oaicite:30]{index=30}", "### Empty (first run)", "“No projects yet. Create your first project to organize your work.” Primary action: “Create project”. :contentReference[oaicite:31]{index=31}", "### Zero results", "“No results for ‘knee brace’.” Suggestions: “Remove filters” / “Search for a broader term” / “Check spelling”.", "### Permission state", "“You don’t have access to this report.” Next steps: “Request access” or “Switch account”. Provide a non-blocking path to continue elsewhere."], edgeCases: ["Offline/degraded mode: clearly indicate offline state, preserve user input, and clarify whether actions are queued or must be retried.", "Long-running operations: show progress, allow safe cancellation when possible, and avoid freezing UI; use determinate progress when feasible. :contentReference[oaicite:32]{index=32}", "Rate limits or repeated failures: after multiple retries, change the guidance (wait, try later, contact support) and avoid infinite retry loops.", "Conflicts (simultaneous edits): explain what changed, show differences if possible, and offer a resolution path (keep mine / keep theirs).", "Multi-pane/complex apps: empty states may be local to a panel; provide local next steps without hijacking the entire screen. :contentReference[oaicite:33]{index=33}", "Accessibility: status messages that don’t move focus must still be announced to assistive tech and remain discoverable long enough to be understood. :contentReference[oaicite:34]{index=34}", "Security-sensitive actions: require stronger confirmation only when the action is destructive or irreversible; otherwise prefer undo."], source: "Starter KB compiled from trusted UX guidance and standards (NN/g, Material Design, Apple HIG, WCAG). Key refs: NN/g empty states + button states; Material errors/progress/snackbar/dialogs; Apple HIG loading/progress; WCAG Understanding 4.1.3 Status Messages.", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["ux", "ui", "interaction-design", "design-patterns", "states", "empty-states", "loading", "progress", "notifications", "accessibility"] },
  "platform-guidelines": { id: "platform-guidelines", title: "Platform Guidelines", purpose: "Provide reference knowledge for evaluating and aligning UI designs with platform conventions across iOS, Android (Material), and the web. Helps ensure predictable navigation, appropriate component choices, consistent behaviors, and accessible interaction patterns.", scope: "Applies to user-facing UI design for iOS/iPadOS, Android/Material, and web apps: navigation patterns, common components, interaction behaviors, states, and web semantic expectations. Excludes assistant behavior, output formatting, schema enforcement, and design-system-specific rules (handled by Design System KBs).", definitions: ["### Platform Convention", "A widely expected UI behavior or pattern on a platform (e.g., iOS tab bar for top-level destinations; Material navigation bar/bottom navigation for top-level destinations).", "### Top-level Navigation", "Navigation that switches between primary areas of an app (e.g., tabs / bottom nav).", "### Hierarchical Navigation", "Navigation within a section (e.g., push to detail, back to list).", "### Modal", "A temporary overlay that requires the user to complete or dismiss it before returning to the underlying context (commonly used for focused tasks).", "### Web Semantics", "Using native HTML elements and/or correct ARIA roles/states so assistive technologies can interpret controls and patterns (e.g., combobox behavior)."], rulesConstraints: ["Prefer platform-native patterns for navigation and core controls. Deviations must have a clear user benefit and be applied consistently.", "Use top-level navigation for switching primary destinations; use hierarchical navigation for drilling in/out within a destination.", "Avoid mixing multiple top-level nav paradigms on the same surface (e.g., tab bar + bottom nav) unless there is a strong, well-tested rationale.", "Match component choice to platform expectations: use platform-standard controls for switches, selection, dialogs, and navigation where possible.", "Make interactive states clear and consistent (enabled, disabled, pressed, focused).", "Accessibility is not optional: ensure patterns are operable with assistive tech. On web, prefer native HTML controls; use WAI-ARIA APG patterns when building custom widgets.", "Web forms should support autofill where appropriate; use the standard `autocomplete` tokens and do not invent custom values.", "When designing cross-platform experiences, standardize the underlying IA and tasks, but allow platform-specific UI conventions (e.g., placement of navigation controls) to differ."], doDont: { do: ["Use iOS tab bars for switching between top-level sections and keep destinations stable and recognizable.", "Use Material navigation bars/bottom navigation for 3–5 primary destinations; keep labels clear and consistent.", "Use top app bars for screen-level navigation and actions; keep key actions visible and avoid overcrowding.", "Use dialogs for high-stakes confirmations and complex decisions; prefer non-blocking feedback (snackbars/toasts) for low-risk confirmations and undo.", "On web, use native inputs/buttons/links when possible; for custom widgets, follow WAI-ARIA APG interaction models (keyboard, roles, states).", "For web form fields, specify `autocomplete` where it improves entry speed and accuracy (e.g., name, email, address).", "Design for back/escape behavior: users should be able to leave or undo safely (especially for modals and destructive actions)."], dont: ["Don't reinvent common platform controls (switches, pickers, navigation) without a strong reason; it increases learning cost and accessibility risk.", "Don't hide primary navigation behind ambiguous gestures or icon-only controls without labels when clarity is needed.", "Don't overuse modals; avoid blocking the user for low-risk confirmations or routine feedback.", "Don't create custom web widgets without specifying keyboard behavior, focus management, and ARIA semantics that match an established pattern.", "Don't disable or sabotage web autofill by using nonstandard `autocomplete` values or unusual field structures unless required.", "Don't rely on hover-only interactions for core actions in touch environments."] }, examples: ["### iOS: Top-level navigation", "Use a tab bar to switch between primary areas (e.g., Home, Search, Profile). Keep the same destinations available throughout typical navigation paths.", "### Material: Top app bar + navigation bar", "Use a top app bar for contextual title/actions and a bottom navigation bar for 3–5 primary destinations; avoid placing too many competing actions in the app bar.", "### Web: Combobox vs select", "If users must pick from a large list with type-ahead, use a combobox pattern with correct keyboard support; for a small fixed set, use a native select or radio group.", "### Web: Autofill", "For a shipping address form, include standard `autocomplete` tokens (e.g., `shipping street-address`, `postal-code`) to support browser autofill."], edgeCases: ["Cross-platform parity: keep information architecture consistent, but allow platform-specific UI differences (e.g., iOS uses tab bars and back navigation conventions; Material uses navigation bar/drawer patterns).", "Dense enterprise UIs: prioritize scannability and predictable navigation; avoid hidden actions that require discovery (especially icon-only controls without labels).", "Custom components: when not using native controls, explicitly define keyboard interaction, focus order, and accessible roles/states; reference ARIA APG patterns for web.", "Hybrid apps (web in mobile shells): be careful mixing web patterns with native expectations; validate back behavior, modal dismissal, and focus/keyboard interactions.", "Internationalization: ensure labels fit longer strings; avoid hard-coded truncation that hides meaning in navigation destinations and key actions."], source: "Starter KB compiled from primary platform guidance: Apple Human Interface Guidelines (iOS/iPadOS/macOS), Material Design (Android/Web), WAI-ARIA Authoring Practices (web interaction patterns), and MDN/WHATWG HTML guidance (web form behaviors like autocomplete).", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["platform-guidelines", "ios", "android", "web", "interaction-design", "navigation", "components", "accessibility", "conventions"] },
  "service-design": { id: "service-design", title: "Service Design", purpose: "Provide reference knowledge for designing and evaluating end-to-end services (not just UI): how user journeys, people, processes, and technical systems work together; how failures are handled; and how operational readiness (SLOs, incident response, observability) is designed into the service.", scope: "Applies to service-level design and validation across channels and systems: service blueprints, touchpoints, backstage processes, ownership, dependencies, environments, reliability expectations, failure modes, and operational processes (incident/problem/change). This starter KB is intentionally generic and should be extended with org-specific architecture, SLAs/SLOs, environment details, and runbooks. Excludes assistant behavior, output formatting rules, and any proprietary infrastructure details unless supplied in a private KB.", definitions: ["### Service Design", "Planning and organizing resources (people, processes, supporting technology, and evidence) to improve the customer and employee experience across an end-to-end service.", "### Service Blueprint", "A diagram that visualizes the relationships between touchpoints in the customer journey and the behind-the-scenes people/process/technology needed to deliver them.", "### Customer Journey", "The user's end-to-end experience across steps and channels to accomplish a goal (often includes emotions, pain points, and outcomes).", "### Touchpoint", "A point of interaction between the user and the service (UI screen, email, support contact, notification, IVR, etc.).", "### Frontstage", "Visible interactions and evidence the user experiences (UI, copy, confirmations, notifications).", "### Backstage", "Behind-the-scenes work and systems enabling the frontstage experience (services, queues, support operations, policies).", "### Service Contract", "A clear statement of what the service provides, for whom, under what constraints, including reliability and support expectations.", "### SLA", "A formal agreement describing service expectations and remedies (often external/customer-facing).", "### SLI", "Service Level Indicator: a measurable metric of service behavior (availability, latency, correctness).", "### SLO", "Service Level Objective: a target level for an SLI over a time window (e.g., 99.9% successful requests).", "### Error Budget", "A reliability “allowance” derived from an SLO (approximately 1 - SLO) used to balance shipping velocity with stability.", "### Incident", "An unplanned interruption or degradation of service requiring response to restore normal operation.", "### Problem", "The underlying cause (or potential cause) of one or more incidents; problem management focuses on preventing recurrence.", "### Change", "A modification to a system/service that can affect users (deployment, config change, migration).", "### Environment", "A deployment context (dev/staging/prod) with distinct data, configs, and release controls.", "### Observability", "The ability to understand system state from outputs: logs, metrics, traces, and user-visible health signals.", "### Runbook", "A step-by-step operational guide to diagnose and resolve known failure modes."], rulesConstraints: ["Design for the service, not the screen: validate that each user step has corresponding backstage processes and system dependencies.", "For each critical user journey, document: entry conditions, success outcomes, failure modes, and recovery paths.", "Map ownership: every touchpoint and dependency should have a clear owner (team or role) and escalation path.", "Define reliability targets at the service level (SLOs/SLIs) for critical journeys; align release velocity to error budgets when used.", "Prefer graceful degradation over hard failure: when dependencies fail, provide partial functionality or clear next steps when feasible.", "Avoid silent failure: user-visible outcomes must reflect real system state (no false success).", "Data integrity and privacy are non-negotiable: define where sensitive data is stored/transmitted and how it is protected.", "Operational readiness is part of definition of done for major service changes: monitoring, alerting, dashboards, and runbooks must exist for critical paths.", "Incident communications should be designed: status messaging, user guidance, and support workflows must be consistent and truthful.", "Changes should be reversible when possible: support rollback strategies, feature flags, and safe migration paths."], doDont: { do: ["Create a service blueprint for key journeys: frontstage steps + backstage processes + systems + evidence + handoffs.", "Identify top risks per journey: dependency outages, latency spikes, data conflicts, permission failures, rate limits, and user error.", "Define service contracts for core capabilities: what's supported, what's not, constraints, and expected behavior.", "Define standard failure responses: retry semantics, queuing, offline mode, idempotency, and conflict resolution rules.", "Design support touchpoints: self-serve help, contact support, escalation, and status pages where appropriate.", "Instrument critical paths: success/failure rates, latency, and user-perceived performance signals.", "Provide user-safe defaults and recovery: preserve work, autosave drafts, and allow resuming after interruptions.", "Document environment parity expectations: what differs between staging and production and how to test safely."], dont: ["Don't treat service design as documentation-only; it must influence UI states, backend contracts, and operational readiness.", "Don't ship a journey without defined failure modes and recovery paths (including partial success).", "Don't rely on manual heroics: if something breaks repeatedly, add automation/runbooks and reduce recurrence.", "Don't hide dependencies: if a feature relies on external systems, design visible states for outages and latency.", "Don't design operational processes that depend on tribal knowledge; encode them in runbooks and dashboards.", "Don't conflate incidents with problems: restore service first, then investigate root causes and prevention."] }, examples: ["### Service blueprint slice (example)", "Frontstage: User submits payment → sees “Processing…” → receives confirmation. Backstage: API validates → payment processor call → ledger write → receipt email → analytics event. Failure modes: processor timeout, duplicate submit, ledger conflict. Recovery: retry with idempotency key, queued receipt, visible status.", "### Reliability target example", "SLO: 99.9% successful checkout requests over 28 days. SLI: proportion of successful checkout API calls under latency threshold. Use error budget to gate risky releases when budget is exhausted.", "### Incident-ready UI states", "If dependency is down: show degraded mode banner + limited actions + retry + link to status/help, while preserving user progress.", "### Ownership and escalation", "Touchpoint owner: Checkout PM + Checkout Eng. Dependency owner: Payments Platform. Escalation: on-call rotation + incident channel + runbook link."], edgeCases: ["Cross-channel journeys: user starts in-app, continues via email link, completes on web-ensure identity, state, and permissions remain consistent.", "Partial success: some actions complete but downstream steps fail (e.g., saved order but receipt email fails)-design explicit messaging and back-office reconciliation.", "Long-running operations: provide progress, allow safe cancellation, and ensure the user can return later without losing work.", "Offline/degraded networks: clarify what is queued vs what requires connectivity; avoid ambiguous “saved” claims when not persisted.", "Data migrations and schema changes: design compatibility windows, progressive rollout, and rollback; ensure UI can handle mixed states.", "Multi-tenant/role-based systems: permission boundaries must be validated at every touchpoint; design clear request-access flows."], source: "Starter/placeholder KB based on established service design + reliability practices (NN/g service design + service blueprints; Google SRE SLOs/error budgets). Intended to be customized for private/work environments with system-specific service maps, ownership, environments, and operational runbooks.", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["service-design", "service-blueprint", "journey-mapping", "operations", "reliability", "sre", "incident-management", "observability", "handoff", "systems-thinking"] },
  "test-kb": { id: "test-kb", title: "Test Knowledge Base", purpose: "This is a test knowledge base used to validate the KB system.", scope: "Used only for testing ACE normalization and plugin wiring.", definitions: [], rulesConstraints: ["Always respond clearly.", "Do not hallucinate missing information."], doDont: { do: ["Follow instructions exactly."], dont: ["Make assumptions."] }, examples: ["If asked “What is this?”, respond “This is a test.”"], edgeCases: ["Empty input."], updatedAt: "2026-02-07T00:25:31.744Z" },
  "ux-research": { id: "ux-research", title: "UX Research", purpose: "Provide reference knowledge for planning, running, and applying UX research in a way that produces credible, actionable insights. This is a starter KB intended to be extended in private/work settings with internal research repositories, customer segments, prior findings, and domain-specific constraints.", scope: "Applies to UX research activities that inform product/design decisions: discovery (needs, JTBD), evaluative research (usability tests, concept tests), mixed methods, synthesis (coding, themes), and insight communication. Includes guidance for turning findings into design requirements and validation criteria. Excludes company-specific findings and sensitive participant data; those belong in private KBs with governance.", definitions: ["### Research Question", "A specific question the study aims to answer (e.g., \"Can users find X?\" \"Why do users abandon Y?\") that guides method, tasks, and analysis.", "### Study Goal", "The outcome the research must enable (decision to make, risk to reduce, hypothesis to validate).", "### Method", "A structured approach to data collection (e.g., moderated usability test, unmoderated test, interview, diary study, survey, analytics review).", "### Discovery Research", "Research to understand user needs, motivations, context, and problems (what to build and why).", "### Evaluative Research", "Research to evaluate a design or product against tasks and success criteria (how well it works).", "### Usability Test", "A session where participants attempt realistic tasks while the researcher observes behavior and collects feedback.", "### Task Scenario", "A realistic prompt that encourages an action without telling the user how to use the interface.", "### Finding", "An observed issue or behavior supported by evidence (quote, video/timecode, metric).", "### Insight", "A decision-ready interpretation of findings that explains why something happens and what it implies for the product/design.", "### Recommendation", "An actionable change proposed based on the evidence, scoped to what should change and why.", "### Thematic Analysis", "A method for analyzing qualitative data by coding and grouping patterns into themes.", "### Code", "A label applied to a piece of qualitative data (quote/observation) that captures what it is about.", "### Theme", "A meaningful pattern across multiple data points (multiple coded instances).", "### Affinity Diagramming", "A collaborative method to cluster research findings into groups to reveal patterns.", "### HEART Metrics", "A UX measurement framework: Happiness, Engagement, Adoption, Retention, Task Success.", "### Evidence", "Verifiable support for a claim: direct quote, screenshot, timecode, task outcome, or metric."], rulesConstraints: ["Start with the decision: define the decision to make, risks to reduce, and what would change based on results.", "Define 1-3 primary research questions; avoid sprawling studies that cannot be analyzed or acted on.", "Use realistic task scenarios that encourage action without giving away the UI path.", "Separate observation from interpretation: document what happened (finding) distinct from why (insight).", "Capture evidence for each key finding (quote/timecode/task outcome) so results are audit-able.", "For evaluative research, define success criteria up front (task success, time on task, errors, confidence).", "Do not generalize beyond the sample: qualitative studies produce direction, not statistical proof unless designed for it.", "Synthesize systematically: code data, group into themes, validate themes for fit, then derive insights and opportunities.", "Prioritize findings by impact on user outcomes and frequency; avoid prioritizing by emotional intensity alone.", "Maintain participant privacy: avoid storing personal identifiers or sensitive data in public KBs or design files.", "Inclusive research: consider accessibility needs and diverse participants; ensure study materials and prototypes are usable with assistive technologies where relevant.", "Operational discipline: record study date, product version/prototype version, method, participants, and constraints so findings remain interpretable over time."], doDont: { do: ["Write a short study brief: goals, questions, method, participant criteria, tasks, success metrics, logistics.", "Pilot the session with 1 participant or internal dry-run to catch task ambiguity and prototype issues.", "Use neutral facilitation: avoid leading questions; ask for expectations before showing solutions.", "Use task scenarios that reflect real user goals and context (not UI instructions).", "Take structured notes and tag them for synthesis (chronological log + codes).", "Synthesize soon after sessions while context is fresh; use thematic analysis or affinity mapping.", "Turn insights into actions: design requirements, backlog items, experiment hypotheses, or acceptance criteria.", "Communicate results with a tight structure: executive summary, top findings, evidence, recommendations, risks/unknowns.", "Where useful, pair qualitative insights with signals/metrics (e.g., HEART Task Success).", "Maintain a research repository: searchable findings, themes, and links to evidence (private/work setting)."], dont: ["Don't start with a solution and use research to justify it; treat research as a way to reduce uncertainty.", "Don't use unrealistic tasks or instruct users how to complete tasks; it invalidates the test.", "Don't collapse findings and recommendations into one statement without evidence.", "Don't treat 5-user qualitative testing as statistically representative; use it to find issues and patterns.", "Don't ignore context: segment differences (new vs expert, mobile vs desktop) often explain conflicting feedback.", "Don't ship research outputs without a clear \"so what\": what changes, who owns it, and when it will be validated again.", "Don't store raw sensitive participant information in shared artifacts; redact and minimize."] }, examples: ["### Study goal (evaluative)", "Determine whether users can create and share a report in under 2 minutes without assistance.", "### Research questions", "1) Can users find the entry point to create a report? 2) Do users understand required inputs? 3) Can users recover from common errors?", "### Task scenario (good)", "You need to share a weekly report with your team by end of day. Create a new report for this week and share it with a colleague.", "### Finding (with evidence)", "Users missed the primary \"Create report\" action because it was grouped with secondary actions. Evidence: 4/6 participants scanned the sidebar twice and clicked \"Templates\" first; quote: \"I expected it under Reports.\"", "### Insight", "Users rely on the sidebar label structure more than iconography for navigation; when the mental model is category-first, actions hidden in toolbars are less discoverable.", "### Recommendation", "Move \"Create report\" to the top of the Reports section and label it as a primary action; keep toolbar actions secondary. Validate with a follow-up usability test focused on discoverability.", "### Synthesis output", "Theme: \"Navigation labels drive discovery.\" Codes: \"missed primary action,\" \"sidebar scan,\" \"icon confusion.\""], edgeCases: ["Conflicting findings across segments: split results by segment (role, experience, device) and design for the dominant workflow while providing escape hatches.", "Prototype fidelity issues: if the prototype lacks realistic data/states, findings may reflect prototype limitations rather than true usability problems; document constraints.", "Artificial tasks: if tasks are not meaningful to participants, behavior will be distorted; rewrite scenarios to match real goals and incentives.", "Remote testing constraints: connectivity, screen sharing, and audio issues can affect results; plan contingencies and note disruptions.", "Sensitive domains: avoid collecting or recording confidential data; use synthetic data sets and redact recordings/transcripts.", "AI-assisted synthesis: if using AI to help code/summarize, treat outputs as drafts; verify against raw evidence and preserve traceability to quotes/timecodes.", "Time pressure: when rapid feedback is needed, run a small evaluative test with tight scope; clearly label confidence and what remains unknown."], source: "Starter/placeholder KB grounded in established UX research practice. Primary references: NN/g guidance on usability testing, task scenarios, qualitative analysis (thematic analysis, coding), group notetaking, and affinity diagramming; HEART UX metrics framework; WCAG Understanding for inclusive considerations. Examples of primary refs: https://www.nngroup.com/articles/usability-testing-101/ ; https://www.nngroup.com/articles/task-scenarios-usability-testing/ ; https://www.nngroup.com/articles/thematic-analysis/ ; https://www.nngroup.com/articles/affinity-diagram/ ; https://www.nngroup.com/articles/group-notetaking/ ; https://www.heartframework.com/ ; https://www.w3.org/TR/WCAG22/", updatedAt: "2026-02-07T00:00:00.000Z", version: "1.0", tags: ["ux-research", "user-research", "usability-testing", "qualitative", "quantitative", "synthesis", "interviews", "surveys", "journey-mapping", "metrics"] },
}
